import{_ as i,o as a,c as t,ag as r}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"Policies","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/40_policies/_index.md","filePath":"10_core/10_governance/40_policies/_index.md"}'),o={name:"10_core/10_governance/40_policies/_index.md"};function n(l,e,s,c,u,d){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="policies" tabindex="-1">Policies <a class="header-anchor" href="#policies" aria-label="Permalink to &quot;Policies&quot;">​</a></h1><p>Policies define how the QiAccess Start master blueprint is operated and changed.</p><h2 id="merge-policy" tabindex="-1">Merge Policy <a class="header-anchor" href="#merge-policy" aria-label="Permalink to &quot;Merge Policy&quot;">​</a></h2><ul><li>Prefer formal sources over informal ones.</li><li>ADRs must exist before merging structural changes to roots, routing, schema ownership, or topology.</li><li>Drift between doctrine and implementation must be flagged and resolved.</li></ul><h2 id="root-navigation-policy" tabindex="-1">Root Navigation Policy <a class="header-anchor" href="#root-navigation-policy" aria-label="Permalink to &quot;Root Navigation Policy&quot;">​</a></h2><ul><li>The active portal has seven top-level roots only.</li><li>New user-facing concerns belong inside an existing root unless a blueprint change explicitly approves a new root.</li><li>System subroutes remain nested under <code>System</code>.</li></ul><h2 id="placement-policy" tabindex="-1">Placement Policy <a class="header-anchor" href="#placement-policy" aria-label="Permalink to &quot;Placement Policy&quot;">​</a></h2><ul><li>Placement is based on operational ownership, not technical convenience.</li><li>A file, record, or page belongs to the layer that owns its lifecycle.</li><li>When ownership is ambiguous, escalate to an ADR before placing.</li></ul><h2 id="lifecycle-policy" tabindex="-1">Lifecycle Policy <a class="header-anchor" href="#lifecycle-policy" aria-label="Permalink to &quot;Lifecycle Policy&quot;">​</a></h2><p>Objects and records progress through lifecycle states:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>active -&gt; deprecated -&gt; archived</span></span></code></pre></div><ul><li><strong>Active</strong>: in use, maintained, and part of current truth</li><li><strong>Deprecated</strong>: retained but not extended; must be marked clearly</li><li><strong>Archived</strong>: no longer active; preserved for lineage only</li></ul><p>Documentation quarantine is an additional handling rule for legacy doctrine. Quarantined material may be retained for salvage, but it is not active doctrine.</p><h2 id="bootstrap-policy" tabindex="-1">Bootstrap Policy <a class="header-anchor" href="#bootstrap-policy" aria-label="Permalink to &quot;Bootstrap Policy&quot;">​</a></h2><ul><li>No undocumented dependencies allowed at bootstrap.</li><li>Every environment variable and runtime dependency should be documented before it is treated as required.</li><li>Every service dependency should be verified before a page claims it is operational.</li></ul><h2 id="registry-policy" tabindex="-1">Registry Policy <a class="header-anchor" href="#registry-policy" aria-label="Permalink to &quot;Registry Policy&quot;">​</a></h2><ul><li>Classification happens via explicit registry or documented ownership, not assumptions.</li><li>No governed object should enter the system without a canonical identifier or clear owning reference.</li><li>Registry issuance and naming decisions must be traceable.</li></ul><h2 id="contribution-policy" tabindex="-1">Contribution Policy <a class="header-anchor" href="#contribution-policy" aria-label="Permalink to &quot;Contribution Policy&quot;">​</a></h2><p>All contributors, human or AI, must:</p><ul><li>avoid parallel schemas or shadow structures without ADR review</li><li>avoid creating new root structures without blueprint approval</li><li>maintain single ownership for canonical objects</li><li>treat exports and AI outputs as derived</li><li>respect registry and naming rules where used</li><li>document build and validation steps</li><li>prioritize clarity over cleverness</li></ul><h2 id="active-runtime-policy" tabindex="-1">Active Runtime Policy <a class="header-anchor" href="#active-runtime-policy" aria-label="Permalink to &quot;Active Runtime Policy&quot;">​</a></h2><ul><li>The current QiAccess Start runtime is single-user and operator-centered unless a page explicitly marks another model as future-state.</li><li>Current access control should default to owner-scoped or protected system-scoped behavior, not assumed tenant scaffolding.</li><li>Older multi-tenant language may be retained for history, but it must be labeled as future-state or quarantined.</li></ul><h2 id="security-and-data-access-policy" tabindex="-1">Security and Data Access Policy <a class="header-anchor" href="#security-and-data-access-policy" aria-label="Permalink to &quot;Security and Data Access Policy&quot;">​</a></h2><ul><li><strong>Anon Zero-Write Law</strong>: Public unauthenticated access is read-only by default and must not write to canonical records directly.</li><li><strong>System Role Isolation</strong>: Elevated service credentials belong only to trusted backend, worker, or controlled automation paths.</li><li><strong>Protected Surface Rule</strong>: Private infrastructure such as server admin, storage internals, diagnostics, and raw runtime control stays behind explicit protection boundaries.</li><li><strong>Derived Truth Rule</strong>: Search, AI, graph, and export layers may assist but may not silently replace canonical sources.</li></ul><h2 id="legacy-quarantine-policy" tabindex="-1">Legacy Quarantine Policy <a class="header-anchor" href="#legacy-quarantine-policy" aria-label="Permalink to &quot;Legacy Quarantine Policy&quot;">​</a></h2><ul><li>Legacy QiOS, QiOne, tenant, client, and business-delivery doctrine may be preserved for salvage.</li><li>When such material conflicts with the active seven-root portal, it must be moved to or referenced from the quarantine appendix.</li><li>Quarantined pages are reference-only until revalidated by blueprint update or ADR.</li></ul><h2 id="agent-governance-policy" tabindex="-1">Agent Governance Policy <a class="header-anchor" href="#agent-governance-policy" aria-label="Permalink to &quot;Agent Governance Policy&quot;">​</a></h2><p>QiAccess Start still enforces an Agent Governance Layer.</p><p>Agents must:</p><ul><li>validate doctrine before making structural changes</li><li>preserve canonical versus derived boundaries</li><li>treat external or reconciled notes as non-authoritative until checked against the active blueprint</li><li>escalate when ownership, route, or truth status is unclear</li></ul><h2 id="phase-0-�-freeze-and-protect-qinexus" tabindex="-1">Phase 0 � Freeze and protect (QiNexus) <a class="header-anchor" href="#phase-0-�-freeze-and-protect-qinexus" aria-label="Permalink to &quot;Phase 0 � Freeze and protect (QiNexus)&quot;">​</a></h2><p>Goal: prevent accidental loss during reorganization.</p><p><strong>Mandatory Rules:</strong></p><ul><li>Do not delete anything.</li><li>Do not let an AI move files directly.</li><li>Create and use the \\130_system/qinexus_cleanup\\ folder.</li><li>Generate manifests and reports before any moves.</li></ul><h3 id="cleanup-system-structure" tabindex="-1">Cleanup System Structure <a class="header-anchor" href="#cleanup-system-structure" aria-label="Permalink to &quot;Cleanup System Structure&quot;">​</a></h3><p>Located at \\G:\\My Drive\\QiNexus\\130_system\\qinexus_cleanup:</p><ul><li><br> ules/: Governance and movement criteria.</li><li><br> eports/: Audit results and analysis.</li><li>\\manifests/: Snapshots of directory state.</li><li>\\quarantine/: Staging for disputed or risky items.</li><li>\\scripts/: Automation for audit and verification.</li><li>\\\x07pproved_moves/: Verified move instructions for human execution.</li></ul>',37)])])}const y=i(o,[["render",n]]);export{h as __pageData,y as default};
